    .replace(/\b10s\b/gi, '5s')
}));

const wsKey = $env.WAVESPEED_API_KEY || '';
if (!wsKey) console.warn('WARNING: WAVESPEED_API_KEY not set — Seedance calls will fail');

console.log('Stage 2 start | job:', body.job_id, '| scenes:', scenes.length, '| topic:', body.topic);

return [{ json: {
  ...body,
  scenes,
  num_clips:    scenes.length,
  clip_dur_sec: 5,
