const fs            = require('fs');
const { execSync }  = require('child_process');

const jobData = $('Extract & Prepare').first().json;
const jobId   = jobData.job_id;
const narration = (jobData.narration || '').substring(0, 3000);
const n8nIn   = '/data/ffmpeg/input';

if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

// Write narration to file — avoids all escaping problems
const narrationFile = n8nIn + '/' + jobId + '_narration.txt';
fs.writeFileSync(narrationFile, narration, 'utf8');

// Write Python script to shared volume
const scriptPath  = n8nIn + '/' + jobId + '_tts.py';
const containerBase = '/ffmpeg/input/' + jobId;

const pythonScript = `import asyncio, edge_tts, json

async def main():
    with open('${containerBase}_narration.txt', 'r', encoding='utf-8') as f:
        narration = f.read()
    job_id = '${jobId}'

    comm = edge_tts.Communicate(narration, voice='en-US-EmmaNeural', rate='-5%', pitch='+2Hz')
    audio_bytes = b''
    sentences = []

    async for chunk in comm.stream():
        if chunk['type'] == 'audio':
            audio_bytes += chunk['data']
        elif chunk['type'] == 'SentenceBoundary':
            sentences.append({
                'text': chunk['text'],
                'start': chunk['offset'] / 10000000,
                'end': (chunk['offset'] + chunk['duration']) / 10000000
            })

    audio_path = '/ffmpeg/input/' + job_id + '_voice.mp3'
    with open(audio_path, 'wb') as f:
        f.write(audio_bytes)

    word_timings = []
    if sentences:
        for sent in sentences:
            sent_words = sent['text'].strip().split()
            if not sent_words:
                continue
            duration = sent['end'] - sent['start']
            total_chars = sum(len(w) for w in sent_words)
            cursor = sent['start']
            for w in sent_words:
                word_dur = (len(w) / max(total_chars, 1)) * duration
                word_timings.append({
                    'word': w.rstrip('.,!?;:'),
                    'start': round(cursor, 3),
                    'end': round(cursor + word_dur, 3)
                })
                cursor += word_dur
    else:
        cursor = 0.1
        for w in narration.strip().split():
            dur = 0.38 * (0.8 + len(w) * 0.04)
            word_timings.append({'word': w, 'start': round(cursor, 3), 'end': round(cursor + dur, 3)})
            cursor += dur

    audio_duration = sentences[-1]['end'] + 0.5 if sentences else (word_timings[-1]['end'] + 0.5 if word_timings else 30)

    result = {'audio_path': audio_path, 'audio_duration': round(audio_duration, 3), 'word_timings': word_timings}
    with open('/ffmpeg/input/' + job_id + '_timings.json', 'w') as f:
        json.dump(result, f)
    print('Words:', len(word_timings), '| Duration:', round(audio_duration, 2), 's | Voice: en-US-AnaNeural')

asyncio.run(main())
`;

