function toASS(sec) {
  if (sec === null || sec === undefined || isNaN(sec)) sec = 0;
  const h  = Math.floor(sec / 3600);
  const m  = Math.floor((sec % 3600) / 60);
  const s  = Math.floor(sec % 60);
  const cs = Math.round((sec % 1) * 100);
  return h + ':' + String(m).padStart(2,'0') + ':' + String(s).padStart(2,'0') + '.' + String(cs).padStart(2,'0');
}

// ASS colour format: BGR  — yellow = B:00 G:FF R:FF = &H00FFFF&
// No \t() mixed with \c — keeps libass happy
const Y = '{\\c&H00FFFF&}';  // yellow
const W = '{\\c&HFFFFFF&}';  // white

// Square content area: y=420..1499 inside 1080x1920
// With alignment=2 (bottom-centre), dialogue MarginV controls position:
//   text_bottom_y = PlayResY - MarginV  →  1920 - 450 = 1470  (29px above content edge)
// For j=0 only: add \move tag so the group slides up on first word (pop-in once per group)
// j>0 words: NO position tag — MarginV alone holds them steady at y=1470

const CHUNK = 3;
const dialogueLines = [];

for (let i = 0; i < wordTimings.length; i += CHUNK) {
  const chunk      = wordTimings.slice(i, Math.min(i + CHUNK, wordTimings.length));
  const chunkWords = chunk.map(w => w.word);

  for (let j = 0; j < chunk.length; j++) {
    const wStart = chunk[j].start;
    const wEnd   = chunk[j].end;

    // Active word yellow, others white
    const parts = chunkWords.map((w, k) => (k === j ? Y : W) + w).join(' ') + W;

    // j=0: slide group up from y=1495 → y=1470 (MarginV 425→450 equivalent via move)
    // j>0: no position tag — MarginV=450 keeps text at y=1470 without re-animating
    const moveTag = (j === 0) ? '{\\move(540,1495,540,1470,0,200)}' : '';

    // MarginV=450 in dialogue line overrides style MarginV → text bottom at 1920-450=1470
    dialogueLines.push(
      'Dialogue: 0,' + toASS(wStart) + ',' + toASS(wEnd) + ',Caption,,0,0,450,,' + moveTag + parts
    );
  }
}

